# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._validate_strategy","kind":"function","src_hash":"7a0ebdcc00e4971f","in":{"base":"VerifiedAnnotation"},"out":{"base":"Any"},"spec":{"lhs":"_validate_strategy(ann)","rhs":"strategy-specific validation beyond structural check_proof","over":{"base":"VerifiedAnnotation"},"name":"_validate_strategy_correct"},"guarantee":"strategy-specific validation beyond structural check_proof","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._validate_strategy_correct","statement":"Path(_validate_strategy(x), strategy-specific validation beyond structural check_proof)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"bf79be62eb17463a"}
def _validate_strategy(ann: VerifiedAnnotation,
                        errors: List[str], warnings: List[str]):
    """Strategy-specific validation beyond structural check_proof."""
    s = ann.strategy

    if s in ("library_axiom", "delegation"):
        lib_name = ann.proof_details.get("library", "")
        axiom_name = ann.proof_details.get("axiom_name", "")
        if lib_name:
            lib = get_library(lib_name)
            if lib is None:
                # Auto-registered libs are OK — just warn
                warnings.append(f"no registered theory for '{lib_name}'")
            elif axiom_name and lib.get_axiom(axiom_name) is None:
                warnings.append(f"axiom '{axiom_name}' not in {lib_name} theory")

    elif s == "refinement_descent":
        if not ann.fibers:
            errors.append("refinement_descent: no fibers")
        for fiber in ann.fibers:
            try:
                parse_predicate(fiber.predicate)
            except Exception as e:
                warnings.append(f"fiber '{fiber.name}' predicate: {e}")

    elif s == "mathlib":
        theorem = ann.proof_details.get("theorem_name", "")
        if not theorem:
            errors.append("mathlib: no theorem_name")

    elif s == "transport":
        if not ann.paths:
            warnings.append("transport: no cubical paths specified")


