# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._build_step_proof","kind":"function","src_hash":"c247e46129b4abcc","in":{"base":"Dict[str, Any]"},"out":{"base":"ProofTerm"},"spec":{"lhs":"_build_step_proof(ste)","rhs":"build a proof for one step in a path composition or case split","over":{"base":"Dict[str, Any]"},"name":"_build_step_proof_correct","kind":"composition"},"guarantee":"build a proof for one step in a path composition or case split","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"Refl","by":"library_axiom"},{"fn":"app","by":"library_axiom"},{"fn":"var","by":"library_axiom"},{"fn":"var","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8851eb66c9f8454a"}
def _build_step_proof(step: Dict[str, Any], ann: VerifiedAnnotation) -> ProofTerm:
    """Build a proof for one step in a path composition or case split."""
    s = step.get("strategy", "library_axiom")
    if s == "refl":
        return Refl(app(var(ann.symbol), var("x")))
    if s in ("library_axiom", "delegation"):
        return LibraryAxiom(
            library=step.get("library", ann.symbol.split(".")[0]),
            axiom_name=step.get("axiom_name", "step"),
            statement=step.get("statement", ""),
        )
    if s == "mathlib":
        return MathLibAxiom(theorem_name=step.get("theorem_name", ""))
    return Assume(statement=step.get("statement", "step"))


