# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._spec_from_docstring","kind":"function","src_hash":"49955f1e9df3aa37","in":{"base":"Definition"},"out":{"base":"str"},"spec":{"lhs":"_spec_from_docstring(def)","rhs":"build a path theorem guarantee from the docstring","over":{"base":"Definition"},"name":"_spec_from_docstring_correct"},"guarantee":"build a path theorem guarantee from the docstring","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._spec_from_docstring_correct","statement":"Path(_spec_from_docstring(x), build a path theorem guarantee from the docstring)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"577d8aa86481a886"}
def _spec_from_docstring(defn: Definition) -> str:
    """Build a path theorem guarantee from the docstring."""
    if defn.name in _DUNDER_SPECS:
        return _DUNDER_SPECS[defn.name]
    if defn.kind == DefKind.PROPERTY:
        return f"returns the {defn.name} attribute"
    if defn.kind == DefKind.CLASS:
        return f"correctly constructs a {defn.name} instance"
    doc = defn.docstring
    if not doc:
        if defn.name.startswith("_"):
            return f"internal helper behaves correctly"
        return f"{defn.name} produces the expected output"
    first = doc.split("\n\n")[0].split(". ")[0].strip()
    first = re.sub(r'\s+', ' ', first)
    if len(first) > 200:
        first = first[:200] + "..."
    return first.lower().rstrip(".")


