# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._is_trivial","kind":"function","src_hash":"3df2e11d5dbddd50","in":{"base":"Definition"},"out":{"base":"bool"},"spec":{"lhs":"_is_trivial(def)","rhs":"internal helper behaves correctly","over":{"base":"Definition"},"name":"_is_trivial_correct"},"guarantee":"internal helper behaves correctly","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._is_trivial_correct","statement":"Path(_is_trivial(x), internal helper behaves correctly)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"bbbf8b7eae29c09e"}
def _is_trivial(defn: Definition) -> bool:
    src = defn.source.strip()
    body_lines = []
    in_docstring = False
    past_def = False
    for line in src.split("\n"):
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue
        if not past_def:
            if stripped.startswith(("def ", "async def ", "@")):
                past_def = True
            continue
        if '"""' in stripped or "'''" in stripped:
            if in_docstring:
                in_docstring = False
                continue
            if stripped.count('"""') == 2 or stripped.count("'''") == 2:
                continue
            in_docstring = True
            continue
        if in_docstring:
            continue
        body_lines.append(stripped)
    if not body_lines:
        return True
    if len(body_lines) == 1:
        l = body_lines[0]
        return l in ("pass", "...") or l.startswith("return") or l.startswith("raise NotImplementedError")
    return False


