# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._detect_class_invariants","kind":"function","src_hash":"e090fa5f327fcc3a","in":{"base":"Definition"},"out":{"base":"List[InvariantSpec]"},"spec":{"lhs":"_detect_class_invariants(def)","rhs":"detect class invariants from __init__ assignments and properties","over":{"base":"Definition"},"name":"_detect_class_invariants_correct"},"guarantee":"detect class invariants from __init__ assignments and properties","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._detect_class_invariants_correct","statement":"Path(_detect_class_invariants(x), detect class invariants from __init__ assignments and properties)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a7f2516b4b0f6352"}
def _detect_class_invariants(defn: Definition) -> List[InvariantSpec]:
    """Detect class invariants from __init__ assignments and properties."""
    invariants: List[InvariantSpec] = []
    src = defn.source
    # Properties suggest refinement predicates
    props = re.findall(r'@property\s+def\s+(\w+)', src)
    for p in props:
        if p.startswith("is_"):
            invariants.append(InvariantSpec(
                name=p, predicate=f"self.{p}", kind="class",
                domain=RefinedType(defn.name, "True"),
            ))
    # __init__ assignments define the representation invariant
    init_match = re.search(r'def __init__\(self[^)]*\):[^§]*?(?=\n    def |\Z)', src, re.DOTALL)
    if init_match:
        assignments = re.findall(r'self\.(\w+)\s*=', init_match.group())
        if assignments:
            pred = " and ".join(f"hasattr(self, '{a}')" for a in assignments[:8])
            invariants.append(InvariantSpec(
                name="representation",
                predicate=pred,
                kind="class",
                domain=RefinedType(defn.name, "True"),
                induction_scheme=f"structural on {', '.join(assignments[:4])}",
            ))
    return invariants


