# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._detect_composition","kind":"function","src_hash":"23860b09bc8c6acb","in":{"base":"Definition"},"out":{"base":"Optional[List[str]]"},"spec":{"lhs":"_detect_composition(def)","rhs":"detect if a function is a composition chain: f(g(h(x)))","over":{"base":"Definition"},"name":"_detect_composition_correct"},"guarantee":"detect if a function is a composition chain: f(g(h(x)))","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._detect_composition_correct","statement":"Path(_detect_composition(x), detect if a function is a composition chain: f(g(h(x))))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"4a406d60ba7f6f50"}
def _detect_composition(defn: Definition) -> Optional[List[str]]:
    """Detect if a function is a composition chain: f(g(h(x)))."""
    src = defn.source
    # Find nested function calls in return statements
    ret_match = re.search(r'return\s+(.+)', src)
    if not ret_match:
        return None
    ret_expr = ret_match.group(1).strip()
    # Look for f(g(x)) pattern
    calls: List[str] = []
    depth = 0
    current = ""
    for ch in ret_expr:
        if ch == '(' and current:
            calls.append(current.split('.')[-1])
            current = ""
            depth += 1
        elif ch == ')':
            depth -= 1
        elif ch.isalnum() or ch in '._':
            current += ch
        else:
            current = ""
    if len(calls) >= 2:
        return calls
    return None


