# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._find_imports","kind":"function","src_hash":"30f3b6a39ab6886b","in":{"base":"str","pred":"isinstance(node, ast.Import) and isinstance(node, ast.ImportFrom)"},"out":{"base":"List[str]"},"spec":{"lhs":"_find_imports(sou)","rhs":"internal helper behaves correctly","over":{"base":"str","pred":"isinstance(node, ast.Import) and isinstance(node, ast.ImportFrom)"},"name":"_find_imports_correct"},"guarantee":"internal helper behaves correctly","fibers":[{"name":"ast_Import","pred":"isinstance(node, ast.Import)","path":{"lhs":"_find_imports(x)","rhs":"internal helper behaves correctly","over":{"base":"ast.Import","pred":"isinstance(node, ast.Import)"},"name":"_find_imports_ast.Import_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._find_imports_ast.Import_correct","statement":"_find_imports satisfies spec on ast.Import inputs"},"trust":"LIBRARY"},{"name":"ast_ImportFrom","pred":"isinstance(node, ast.ImportFrom)","path":{"lhs":"_find_imports(x)","rhs":"internal helper behaves correctly","over":{"base":"ast.ImportFrom","pred":"isinstance(node, ast.ImportFrom)"},"name":"_find_imports_ast.ImportFrom_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._find_imports_ast.ImportFrom_correct","statement":"_find_imports satisfies spec on ast.ImportFrom inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":2,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"242269b6da2db807"}
def _find_imports(source: str) -> List[str]:
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return []
    imports: set = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                imports.add(alias.name.split(".")[0])
        elif isinstance(node, ast.ImportFrom) and node.module:
            imports.add(node.module.split(".")[0])
    return sorted(imports)


