    def _parse_json(self, raw: str) -> Optional[Any]:
        try:
            return json.loads(raw)
        except json.JSONDecodeError:
            pass
        for sc, ec in [("{", "}"), ("[", "]")]:
            start = raw.find(sc)
            if start == -1:
                continue
            depth = 0
            for i in range(start, len(raw)):
                if raw[i] == sc:
                    depth += 1
                elif raw[i] == ec:
                    depth -= 1
                    if depth == 0:
                        try:
                            return json.loads(raw[start:i+1])
                        except json.JSONDecodeError:
                            break
        return None

