# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._gen_manifest","kind":"function","src_hash":"5b26eeb8916adc52","in":{"base":"LibraryProofReport"},"out":{"base":"str"},"spec":{"lhs":"_gen_manifest(rep)","rhs":"internal helper behaves correctly","over":{"base":"LibraryProofReport"},"name":"_gen_manifest_correct"},"guarantee":"internal helper behaves correctly","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.library_proof_orchestrator copy 2._gen_manifest_correct","statement":"Path(_gen_manifest(x), internal helper behaves correctly)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"98a8d0e4747e6b83"}
def _gen_manifest(report: LibraryProofReport) -> str:
    lines = [f"# CCTT Proof Manifest: {report.library}", "",
             report.summary(), "", "## Files", "",
             "| File | Defs | Proved | Rate |",
             "|------|------|--------|------|"]
    for rp in sorted(report.file_reports):
        fr = report.file_reports[rp]
        rate = f"{fr.n_proved/fr.n_total:.0%}" if fr.n_total else "N/A"
        lines.append(f"| {rp} | {fr.n_total} | {fr.n_proved} | {rate} |")
    lines += ["", "## Trust Boundary", ""]
    for dep, ver in sorted(report.trust_boundary.items()):
        lines.append(f"- **{dep}** {ver}")
    return "\n".join(lines)


